// ============================================================
// InitCore v1.0 — Gmail Adapter
// Gmail envía notificaciones Pub/Sub con data base64 que contiene
// { emailAddress, historyId }. Necesitamos:
//   1. Decodificar data
//   2. Validar token JWT del header Authorization (firmado por Google)
//   3. Llamar a Gmail API messages.get con el historyId para
//      obtener el mensaje real (se delega a otro nodo HTTP Request)
// ============================================================

const body = $input.first().json.body || {};
const msg = body.message || {};
if (!msg.data) {
  return [{ json: { valid: false, reason: 'Pub/Sub sin data', status: 'rejected' } }];
}

const decoded = Buffer.from(msg.data, 'base64').toString('utf-8');
let parsed;
try { parsed = JSON.parse(decoded); }
catch (e) { return [{ json: { valid: false, reason: 'data no es JSON', status: 'rejected' } }]; }

if (!parsed.emailAddress || !parsed.historyId) {
  return [{ json: { valid: false, reason: 'Falta emailAddress o historyId', status: 'rejected' } }];
}

return [{ json: { valid: true, email: parsed.emailAddress, history_id: parsed.historyId, pubsub_message_id: msg.messageId, publish_time: msg.publishTime } }];

const crypto = require('crypto');
const sha256 = s => crypto.createHash('sha256').update(String(s),'utf-8').digest('hex');
const stripHtml = html => !html ? '' : String(html)
  .replace(/<script[\s\S]*?<\/script>/gi,'')
  .replace(/<style[\s\S]*?<\/style>/gi,'')
  .replace(/<\/?[^>]+>/g,'')
  .replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<')
  .replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#39;|&apos;/gi,"'")
  .replace(/\s+/g,' ').trim();
const normForHash = t => (t||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();

// Extrae el último mensaje no leído y lo convierte a formato InitCore
const items = $input.all();
if (items.length === 0) {
  const payload = { _skip: true, reason: 'Sin mensajes nuevos' };
const message_id = crypto.randomUUID();
const sender_id = sha256(payload.channel + ':' + payload._user_identifier);
const cleanText = stripHtml(payload.message?.text || '');
const mediaFingerprint = (payload.message?.media||[]).map(m => m.url || m.file_id || '').join('|');
const hashKey = normForHash(cleanText);
const hash = sha256(payload.channel + ':' + sender_id + ':' + (hashKey || mediaFingerprint || message_id));

// Flatten out the response so it is easy to persist to messages table, AND hold the 5 fields
const newPayload = {
  channel: payload.channel,
  message_id: message_id,
  sender_id: sender_id,
  user_id: sender_id, // keep it around for the messages table insert
  text: cleanText,
  hash: hash,
  media: payload.message?.media || [],
  ts: payload.timestamp || new Date().toISOString(),
  context: payload.context || {},
  metadata: payload.metadata || {}
};

return [{ json: newPayload }];
